<script setup lang="ts">import{onMounted,ref}from'vue';import{api}from'../api';const rows=ref<any[]>([]);const loading=ref(false);async function load(){loading.value=true;try{rows.value=await api.get('/trade-plans?limit=10')}finally{loading.value=false}}onMounted(load);
</script>
<template><h1 class="page-title">智能选股与交易计划</h1><div class="card"><button class="btn" @click="load">{{loading?'扫描中':'重新扫描'}}</button><table class="table"><thead><tr><th>代码</th><th>评分</th><th>买入区间</th><th>止损</th><th>目标1</th><th>目标2</th><th>仓位</th><th>理由</th></tr></thead><tbody><tr v-for="r in rows" :key="r.symbol"><td>{{r.symbol}}</td><td>{{r.score}}</td><td>{{r.buyLow}}–{{r.buyHigh}}</td><td class="down">{{r.stopLoss}}</td><td class="up">{{r.target1}}</td><td class="up">{{r.target2}}</td><td>{{Number(r.suggestedWeight)*100}}%</td><td>{{r.rationale}}</td></tr></tbody></table></div></template>
